def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    valid_types = {'lang', 'encoding', 'cache'}
    if info_type not in valid_types:
        return header
    header_key = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }[info_type]
    header[header_key] = info_content
    return header

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        full_path = os.path.join(dir_path, filename)
        dir_abs = os.path.abspath(dir_path)
        file_abs = os.path.abspath(full_path)
        if not file_abs.startswith(dir_abs + os.path.sep):
            return ""
        with open(full_path, 'r') as f:
            content = f.read()
        return content
    except Exception as e:
        return ""

import lxml.etree as etree

def get_student_info(xml_data: str, username: str, password: str) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data)
    xpath = f"//student[username='{username}' and password='{password}']"
    students = root.xpath(xpath)
    if len(students) == 1:
        student = students[0]
        return {
            'name': student.find('name').text,
            'citizenship': student.find('citizenship').text,
            'age': student.find('age').text
        }
    return None

